"use client";

import React, { useState, useEffect, useRef } from "react";
import { useRouter } from "next/navigation";
import { logout } from "@/app/auth/actions";

interface MockBookmark {
  title: string;
  url: string;
  tag: string;
}

export const LandingPageClient: React.FC<{ isLoggedIn?: boolean, userEmail?: string, userName?: string, userHandle?: string }> = ({ isLoggedIn, userEmail, userName, userHandle }) => {
  const router = useRouter();

  // Loader states
  const [isLoading, setIsLoading] = useState(true);
  const [loaderExiting, setLoaderExiting] = useState(false);
  const [loadProgress, setLoadProgress] = useState(0);
  const [loaderPhase, setLoaderPhase] = useState(0); // 0=brand, 1=status, 2=ready
  const [statusIndex, setStatusIndex] = useState(0);
  const LOADER_STATUS_LINES = [
    "01 // SECURING ENVIRONMENT",
    "02 // RETRIEVING DIGITAL MEMORIES",
    "03 // CALIBRATING KNOWLEDGE INDEX",
    "04 // RENDERING INTERFACE",
  ];

  // Transition exit state
  const [isExiting, setIsExiting] = useState(false);

  // Mobile Menu state
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Profile Dropdown state
  const [isProfileDropdownOpen, setIsProfileDropdownOpen] = useState(false);
  const dropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target as Node)) {
        setIsProfileDropdownOpen(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  // Scroll reveal states
  const [workflowRevealed, setWorkflowRevealed] = useState(false);
  const [statsRevealed, setStatsRevealed] = useState(false);
  const [featuresRevealed, setFeaturesRevealed] = useState(false);

  // Stats visibility state
  const [statsVisible, setStatsVisible] = useState(false);

  // Workflow simulator state
  const [activeStep, setActiveStep] = useState<number>(1);
  const [simStep2Tags, setSimStep2Tags] = useState<string[]>([]);

  // Feature Playgrounds state
  const [searchQuery, setSearchQuery] = useState("");
  const [tagInput, setTagInput] = useState("");
  const [detectedTags, setDetectedTags] = useState<string[]>([]);
  const [profileHovered, setProfileHovered] = useState(false);
  const [profileLogs, setProfileLogs] = useState<string[]>(["Share your handle: e.g. /@alex"]);

  // Mock search bookmark data
  const MOCK_SEARCH_DATA: MockBookmark[] = [
    { title: "Next.js 16 Routing Guide", url: "nextjs.org/docs", tag: "dev" },
    { title: "Sleek Glassmorphism Effects", url: "glassy.ui/styles", tag: "design" },
    { title: "Introduction to Agentic AI", url: "deepmind.google/ai", tag: "ai" },
    { title: "Advanced CSS Variables", url: "css-tricks.com/vars", tag: "design" },
  ];

  // Phased loader orchestration
  useEffect(() => {
    // Phase 0: Brand reveal (first 400ms handled by CSS animation delays)
    const phaseTimer1 = setTimeout(() => setLoaderPhase(1), 500);

    // Phase 1: Progress bar + cycling status text
    const progressInterval = setInterval(() => {
      setLoadProgress((prev) => {
        if (prev >= 100) {
          clearInterval(progressInterval);
          return 100;
        }
        // Ease-out curve: fast start, slow finish
        const remaining = 100 - prev;
        const step = Math.max(0.5, remaining * 0.06);
        return Math.min(100, prev + step);
      });
    }, 20);

    // Cycle status text every 450ms
    const statusInterval = setInterval(() => {
      setStatusIndex((prev) => {
        if (prev >= 3) {
          clearInterval(statusInterval);
          return 3;
        }
        return prev + 1;
      });
    }, 450);

    // Phase 2: Ready state
    const phaseTimer2 = setTimeout(() => {
      setLoaderPhase(2);
      setLoadProgress(100);
    }, 2200);

    // Exit: curtain-up animation, then hide
    const exitTimer = setTimeout(() => {
      setLoaderExiting(true);
      setTimeout(() => setIsLoading(false), 800);
    }, 2800);

    return () => {
      clearTimeout(phaseTimer1);
      clearInterval(progressInterval);
      clearInterval(statusInterval);
      clearTimeout(phaseTimer2);
      clearTimeout(exitTimer);
    };
  }, []);

  // Intersection Observer for scroll reveals
  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            if (entry.target.id === "workflow") {
              setWorkflowRevealed(true);
            } else if (entry.target.id === "stats") {
              setStatsRevealed(true);
              setStatsVisible(true);
            } else if (entry.target.id === "features") {
              setFeaturesRevealed(true);
            }
          } else {
            if (entry.target.id === "workflow") {
              setWorkflowRevealed(false);
            } else if (entry.target.id === "stats") {
              setStatsRevealed(false);
            } else if (entry.target.id === "features") {
              setFeaturesRevealed(false);
            }
          }
        });
      },
      { threshold: 0.05 }
    );

    const sections = ["workflow", "stats", "features"];
    sections.forEach((id) => {
      const el = document.getElementById(id);
      if (el) observer.observe(el);
    });

    return () => {
      sections.forEach((id) => {
        const el = document.getElementById(id);
        if (el) observer.unobserve(el);
      });
    };
  }, []);



  // Auto-Tag preset analyzer
  useEffect(() => {
    const urlLower = tagInput.toLowerCase();
    if (!urlLower) {
      // eslint-disable-next-line react-hooks/set-state-in-effect
      setDetectedTags([]);
      return;
    }
    const tags: string[] = [];
    if (urlLower.includes("github") || urlLower.includes("next") || urlLower.includes("code")) {
      tags.push("git", "dev", "code");
    }
    if (urlLower.includes("figma") || urlLower.includes("design") || urlLower.includes("ui")) {
      tags.push("figma", "ui-ux", "design");
    }
    if (urlLower.includes("ai") || urlLower.includes("gemini") || urlLower.includes("gpt")) {
      tags.push("ai", "neural", "future");
    }
    if (tags.length === 0) {
      tags.push("saved", "bookmark");
    }
    setDetectedTags(tags);
  }, [tagInput]);

  // Step 2 Tags simulated mount
  useEffect(() => {
    if (activeStep === 2) {
      // eslint-disable-next-line react-hooks/set-state-in-effect
      setSimStep2Tags([]);
      const t1 = setTimeout(() => setSimStep2Tags(["#code"]), 400);
      const t2 = setTimeout(() => setSimStep2Tags(["#code", "#framework"]), 800);
      const t3 = setTimeout(() => setSimStep2Tags(["#code", "#framework", "#git"]), 1200);
      return () => {
        clearTimeout(t1);
        clearTimeout(t2);
        clearTimeout(t3);
      };
    }
  }, [activeStep]);

  // Workspace mock notifications
  const handleCollabAction = (name: string) => {
    const time = new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });
    setCollabLogs((prev) => [`[${time}] ✨ ${name} joined shared pool!`, ...prev.slice(0, 2)]);
  };

  const handleNavigate = (path: string) => {
    setIsExiting(true);
    setTimeout(() => {
      router.push(path);
    }, 450);
  };

  const filteredSearchMock = MOCK_SEARCH_DATA.filter((b) => {
    const lower = searchQuery.toLowerCase();
    return b.title.toLowerCase().includes(lower) || b.tag.toLowerCase().includes(lower);
  });
  return (
    <>
      {/* ═══ Cinematic Luxury Typographic Loader ═══ */}
      {isLoading && (
        <div
          className={`fixed inset-0 z-[100] flex flex-col items-center justify-center bg-[#090908] overflow-hidden ${
            loaderExiting ? "loader-exit" : ""
          }`}
        >
          {/* Breathing ambient champagne glow */}
          <div 
            className="absolute top-1/2 left-1/2 w-[700px] h-[700px] rounded-full bg-[radial-gradient(circle,rgba(217,195,176,0.05)_0%,transparent_70%)] pointer-events-none loader-ambient-glow" 
            style={{ transform: "translate(-50%, -50%)" }}
          />

          <div className="relative flex flex-col items-center justify-center gap-10 text-center max-w-2xl px-6 select-none">

            {/* Minimal logo icon */}
            <img 
              src="/logo.png" 
              alt="EagerMinds Logo" 
              className="animate-cinematic-tagline h-16 w-16 object-contain drop-shadow-[0_10px_20px_rgba(0,0,0,0.12)]" 
              style={{ animationDelay: "0.2s" }}
            />

            {/* Brand Title with Cinematic Letter Expansion & Blur Reveal */}
            <div className="flex flex-col items-center gap-6">
              <h1 
                className="animate-cinematic-title text-4xl sm:text-6xl md:text-7xl font-extralight text-stone-100 tracking-[0.35em] uppercase leading-none"
              >
                EagerMinds
              </h1>

              {/* Tiny minimal percentage loader */}
              <span 
                className="animate-cinematic-tagline text-[10px] font-mono text-stone-500 tracking-[0.25em] tabular-nums"
                style={{ animationDelay: "0.6s" }}
              >
                {Math.round(loadProgress)}%
              </span>
            </div>

          </div>
        </div>
      )}

      {/* Main page layout */}
      <div
        data-vibe="2"
        className={`min-h-screen overflow-x-hidden bg-[#FAF8F5] text-stone-900 font-sans selection:bg-stone-900 selection:text-white transition-colors duration-500 ${
          isExiting ? "animate-exit-fade" : ""
        }`}
      >
        <div className="absolute inset-0 -z-30 h-full w-full bg-[#FAF8F5] bg-[linear-gradient(to_right,#e5e5e030_1px,transparent_1px),linear-gradient(to_bottom,#e5e5e030_1px,transparent_1px)] bg-[size:24px_24px] [mask-image:radial-gradient(ellipse_60%_50%_at_50%_0%,#000_80%,transparent_100%)]" />

        {/* Mobile Menu Overlay */}
        {isMobileMenuOpen && (
          <div className="fixed inset-0 z-50 bg-[#FAF8F5] flex flex-col md:hidden animate-in fade-in zoom-in-95 duration-300">
            <div className="flex h-20 items-center justify-between px-6 sm:px-8 border-b border-stone-200/40">
              <div className="flex items-center gap-3">
                <img 
                  src="/logo.png" 
                  alt="EagerMinds Logo" 
                  className="h-9 w-9 object-contain drop-shadow-sm" 
                />
                <span className="text-sm font-black uppercase tracking-[0.2em] text-stone-900">
                  EagerMinds
                </span>
              </div>
