                  </svg>
                </div>
                <h3 className="text-lg font-black text-stone-900 tracking-tight">Smart Auto-Tag Simulator</h3>

                {/* Tag parser input mock */}
                <input
                  type="text"
                  placeholder="Paste URL (try 'github', 'figma', 'ai')..."
                  value={tagInput}
                  onChange={(e) => setTagInput(e.target.value)}
