              </div>

              {/* Dynamic Parser result tags */}
              <div className="flex-1 w-full bg-stone-50/50 rounded-2xl border border-stone-200/40 p-4 mt-4 flex flex-wrap gap-2 items-center justify-center max-h-36 overflow-y-auto">
