                ))}
              </div>
            </div>

          </div>
        </section>

        <footer className="py-16 text-center text-xs font-bold uppercase tracking-widest text-stone-400 border-t border-stone-200/20 bg-[#F3EFE9]/10">
          <p>© 2026 EagerMinds Bookmarks. All rights reserved.</p>
        </footer>
      </div>
    </>
  );
};

