"use client";

import React, { useState, useEffect, useRef } from "react";
import { useRouter } from "next/navigation";
import { createClient } from "@/utils/supabase/client";
import { logout } from "@/app/auth/actions";

interface Bookmark {
  id: string;
  title: string;
  url: string;
  tag: string;
  notes: string;
  isPublic: boolean;
  createdAt: string;
}

// eslint-disable-next-line @typescript-eslint/no-explicit-any
const mapBookmark = (db: any): Bookmark => ({
  id: db.id,
  title: db.title,
  url: db.url,
  tag: db.tag || "inbox",
  notes: db.notes || "",
  isPublic: db.is_public,
  createdAt: new Date(db.created_at).toISOString().split("T")[0],
});

const isValidUrl = (url: string) => {
  try {
    if (url.length > 2048) return false;
    const parsed = new URL(url);
    if (parsed.protocol !== "http:" && parsed.protocol !== "https:") return false;

    // Require valid domain structure (at least one dot, valid TLD length >= 2)
    // Rejects 'localhost', 'abc', etc.
    const domainRegex = /^[a-zA-Z0-9]([a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(\.[a-zA-Z]{2,})+$/;
    return domainRegex.test(parsed.hostname);
  } catch {
    return false;
  }
};

export const DashboardClient: React.FC = () => {
  const router = useRouter();
  const [supabase] = useState(() => createClient());

  // User Profile
  const [userProfile, setUserProfile] = useState<{ handle: string; full_name: string } | null>(null);

  // Core Bookmarks Database
  const [bookmarks, setBookmarks] = useState<Bookmark[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [activeTab, setActiveTab] = useState<"vault" | "bio" | "tags" | "settings" | "search">("vault");

  const [searchQuery, setSearchQuery] = useState("");
  const [selectedTag, setSelectedTag] = useState<string | null>(null);

  // Inspector & Modal States
  const [selectedCardId, setSelectedCardId] = useState<string | null>(null);
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // New Bookmark Form States
  const [newUrl, setNewUrl] = useState("");
  const [newTitle, setNewTitle] = useState("");
  const [newTag, setNewTag] = useState("");
  const [newNotes, setNewNotes] = useState("");
  const [suggestedTags, setSuggestedTags] = useState<string[]>([]);

  // Keyboard Navigation Index
  const [keyboardIndex, setKeyboardIndex] = useState<number>(-1);

  // Toast System
  const [toast, setToast] = useState<string | null>(null);
  const toastTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  // Dynamic search placeholder for mobile responsiveness
  const [placeholderText, setPlaceholderText] = useState("Search vault...");

  useEffect(() => {
    const updatePlaceholder = () => {
      if (window.innerWidth < 768) {
        setPlaceholderText("Search...");
      } else {
        setPlaceholderText("Search reference vault... (Press '/' to focus)");
      }
    };
    updatePlaceholder();
    window.addEventListener("resize", updatePlaceholder);
    return () => window.removeEventListener("resize", updatePlaceholder);
  }, []);

  // DOM Refs
  const searchInputRef = useRef<HTMLInputElement>(null);

  // Fetch from Supabase on Mount
  useEffect(() => {
    const fetchInitialData = async () => {
      try {
        const { data: { user } } = await supabase.auth.getUser();
        if (user) {
          const { data: profile } = await supabase
            .from("profiles")
            .select("*")
            .eq("id", user.id)
            .maybeSingle();
          if (profile) setUserProfile(profile);

          const { data: bms } = await supabase
            .from("bookmarks")
            .select("*")
            .eq("user_id", user.id)
            .order("created_at", { ascending: false });
          if (bms) {
            setBookmarks(bms.map(mapBookmark));
          }
        }
      } finally {
        setIsLoading(false);
      }
    };
    fetchInitialData();
  }, [supabase]);

  // Toast notifier helper
  const triggerToast = (msg: string) => {
    if (toastTimeoutRef.current) clearTimeout(toastTimeoutRef.current);
    setToast(msg);
    toastTimeoutRef.current = setTimeout(() => {
      setToast(null);
    }, 3000);
  };

  // Tag suggestion parser
  useEffect(() => {
    const urlLower = newUrl.toLowerCase();
    if (!urlLower) {
      // eslint-disable-next-line react-hooks/set-state-in-effect
      setSuggestedTags([]);
      return;
    }
    const tags: string[] = [];
    if (urlLower.includes("github") || urlLower.includes("next") || urlLower.includes("code")) {
      tags.push("nextjs", "git", "dev");
    }
    if (urlLower.includes("figma") || urlLower.includes("design") || urlLower.includes("ui")) {
      tags.push("design", "ui-ux", "figma");
    }
    if (urlLower.includes("ai") || urlLower.includes("gemini") || urlLower.includes("google")) {
      tags.push("ai", "tech", "neural");
    }
    if (urlLower.includes("tailwind") || urlLower.includes("css") || urlLower.includes("vite")) {
      tags.push("framework", "css", "vite");
    }
    if (tags.length === 0) {
      tags.push("ref", "saved");
    }
    setSuggestedTags(tags);
  }, [newUrl]);

  // Filtering Logic
  const filteredBookmarks = bookmarks.filter((b) => {
    const query = searchQuery.toLowerCase();
    const matchesSearch =
      b.title.toLowerCase().includes(query) ||
      b.url.toLowerCase().includes(query) ||
      b.tag.toLowerCase().includes(query) ||
      b.notes.toLowerCase().includes(query);

    const matchesTag = selectedTag ? b.tag.toLowerCase() === selectedTag.toLowerCase() : true;

    return matchesSearch && matchesTag;
  });

  // Calculate unique tags for selector
  const uniqueTags = Array.from(new Set(bookmarks.map((b) => b.tag.toLowerCase()))).filter(Boolean);

  const selectedBookmark = bookmarks.find((b) => b.id === selectedCardId);

  // Keyboard Shortcuts Hook
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const activeElement = document.activeElement;
      const isInputFocused =
        activeElement instanceof HTMLInputElement || activeElement instanceof HTMLTextAreaElement;

      // Escape key handles blur & closures
      if (e.key === "Escape") {
        if (isInputFocused && activeElement instanceof HTMLInputElement) {
          activeElement.blur();
        }
        setIsDrawerOpen(false);
        setIsAddModalOpen(false);
        return;
      }

      // If typing inside an input, don't trigger vault shortcuts
      if (isInputFocused) return;

      // Focus Search: '/'
      if (e.key === "/") {
        e.preventDefault();
        searchInputRef.current?.focus();
        triggerToast("🔍 Search input focused");
        return;
      }

      // New Bookmark Modal: 'N' or 'n'
      if (e.key === "n" || e.key === "N") {
        e.preventDefault();
        setIsAddModalOpen(true);
        triggerToast("✨ Opened add bookmark panel");
        return;
      }

      // Vault cards navigation
      const filteredCount = filteredBookmarks.length;
      if (filteredCount === 0) return;

      if (e.key === "j" || e.key === "J") {
        e.preventDefault();
        setKeyboardIndex((prev) => {
          const next = prev + 1 >= filteredCount ? 0 : prev + 1;
          setSelectedCardId(filteredBookmarks[next].id);
          setIsDrawerOpen(true);
          return next;
        });
      } else if (e.key === "k" || e.key === "K") {
        e.preventDefault();
        setKeyboardIndex((prev) => {
          const next = prev - 1 < 0 ? filteredCount - 1 : prev - 1;
          setSelectedCardId(filteredBookmarks[next].id);
          setIsDrawerOpen(true);
          return next;
        });
      } else if (e.key === "Enter") {
        if (keyboardIndex >= 0 && keyboardIndex < filteredCount) {
          e.preventDefault();
          setSelectedCardId(filteredBookmarks[keyboardIndex].id);
          setIsDrawerOpen(true);
        }
      }
    };

    window.addEventListener("keydown", handleKeyDown);
    return () => window.removeEventListener("keydown", handleKeyDown);
  });

  // Action: Toggle Public Bio-Link Status
  const handleTogglePublic = async (id: string, e: React.MouseEvent) => {
    e.stopPropagation(); // Avoid opening drawer
    const target = bookmarks.find(b => b.id === id);
    if (!target) return;
    const nextState = !target.isPublic;

    // Optimistic UI update
    setBookmarks(prev => prev.map(b => b.id === id ? { ...b, isPublic: nextState } : b));
    triggerToast(
      nextState
        ? "✨ Bookmark added to public Bio Link profile"
        : "🔒 Bookmark removed from public Bio Link"
    );

    // Backend sync
    await supabase.from("bookmarks").update({ is_public: nextState }).eq("id", id);
  };

  // Action: Add Bookmark
  const handleAddBookmark = async (e: React.FormEvent) => {
    e.preventDefault();
    const cleanTitle = newTitle.trim();
    if (!cleanTitle || !newUrl.trim()) {
      triggerToast("⚠️ Please fill in Title and URL");
      return;
    }
    if (cleanTitle.length > 100) {
      triggerToast("⚠️ Title must be 100 characters or less");
      return;
    }

    const cleanUrl = newUrl.trim().startsWith("http") ? newUrl.trim() : `https://${newUrl.trim()}`;
    if (!isValidUrl(cleanUrl)) {
      triggerToast("⚠️ Please enter a valid URL");
      return;
    }

    const { data: { user } } = await supabase.auth.getUser();
    if (!user) return;

    const { data, error } = await supabase.from("bookmarks").insert({
      user_id: user.id,
      title: cleanTitle,
      url: cleanUrl,
      tag: newTag || "inbox",
      notes: newNotes || "",
      is_public: false,
    }).select().maybeSingle();

    if (error || !data) {
      triggerToast("❌ Failed to add bookmark");
      return;
    }

    const newBookmark = mapBookmark(data);
    setBookmarks([newBookmark, ...bookmarks]);
    setIsAddModalOpen(false);

    // Reset Form
    setNewUrl("");
    setNewTitle("");
    setNewTag("");
    setNewNotes("");
    setKeyboardIndex(0);
    setSelectedCardId(newBookmark.id);
    setIsDrawerOpen(true);

    triggerToast("✨ Bookmark added successfully!");
  };

  // Action: Delete Bookmark
  const handleDeleteBookmark = async (id: string) => {
    // Optimistic update
    setBookmarks(prev => prev.filter(b => b.id !== id));
    setIsDrawerOpen(false);
    setSelectedCardId(null);
    setKeyboardIndex(-1);
    triggerToast("🗑️ Bookmark deleted");

    // Backend sync
    await supabase.from("bookmarks").delete().eq("id", id);
  };

  // Action: Save Inspector Drawer Changes
  const handleUpdateBookmark = async (id: string, updates: Partial<Bookmark>) => {
    // Validate title and URL if they are being updated
    if (updates.title !== undefined) {
      const trimmedTitle = updates.title.trim();
      if (!trimmedTitle) {
        triggerToast("⚠️ Title cannot be empty");
        return;
      }
      if (trimmedTitle.length > 100) {
        triggerToast("⚠️ Title must be 100 characters or less");
        return;
      }
      updates.title = trimmedTitle;
    }

    if (updates.url !== undefined) {
      const trimmedUrl = updates.url.trim();
      if (!trimmedUrl) {
        triggerToast("⚠️ URL cannot be empty");
        return;
      }
      const cleanUrl = trimmedUrl.startsWith("http") ? trimmedUrl : `https://${trimmedUrl}`;
      if (!isValidUrl(cleanUrl)) {
        triggerToast("⚠️ Please enter a valid URL");
        return;
      }
      updates.url = cleanUrl;
    }

    // Optimistic update
    setBookmarks(prev => prev.map((b) => b.id === id ? { ...b, ...updates } : b));

    // Map UI updates to DB schema
    const dbUpdates: Record<string, unknown> = {};
    if (updates.title !== undefined) dbUpdates.title = updates.title;
    if (updates.url !== undefined) dbUpdates.url = updates.url;
    if (updates.tag !== undefined) dbUpdates.tag = updates.tag;
    if (updates.notes !== undefined) dbUpdates.notes = updates.notes;
    if (updates.isPublic !== undefined) dbUpdates.is_public = updates.isPublic;

    if (Object.keys(dbUpdates).length > 0) {
      await supabase.from("bookmarks").update(dbUpdates).eq("id", id);
    }
  };

  // Sign out helper
  const handleSignOut = async () => {
    triggerToast("Logging out...");
    await logout();
  };

  return (
    <div className="flex h-screen bg-[#FAF8F5] text-stone-900 overflow-hidden font-sans relative selection:bg-stone-900 selection:text-white">

      {/* Toast Alert Banner */}
      <div
        className={`absolute bottom-6 right-6 z-[70] px-4 py-3 rounded-2xl bg-stone-950 text-white font-mono text-[10px] tracking-wide shadow-2xl flex items-center gap-2 transition-all duration-500 transform ${
          toast ? "opacity-100 translate-y-0" : "opacity-0 translate-y-4 pointer-events-none"
        }`}
      >
        <span>{toast}</span>
      </div>

      {/* Mobile Sidebar Overlay */}
      {isMobileMenuOpen && (
        <div 
          className="fixed inset-0 z-40 bg-stone-900/20 backdrop-blur-sm md:hidden"
          onClick={() => setIsMobileMenuOpen(false)}
        />
      )}

      {/* 1. Sidebar Panel */}
      <aside className={`fixed md:relative inset-y-0 left-0 w-64 border-r border-stone-200/50 bg-[#F4F3EE]/95 md:bg-[#F4F3EE]/50 backdrop-blur-xl md:backdrop-blur-none flex flex-col justify-between shrink-0 z-50 transform transition-transform duration-300 ease-in-out select-none ${isMobileMenuOpen ? "translate-x-0" : "-translate-x-full md:translate-x-0"}`}>
        <div>
          {/* Logo Brand Header */}
          <div className="h-20 px-6 border-b border-stone-200/40 flex items-center justify-between gap-3">
            <div className="flex items-center gap-3">
              <img src="/logo.png" alt="EagerMinds Logo" className="h-8 w-8 object-contain" />
              <span className="text-xs font-black uppercase tracking-[0.25em] text-stone-950">
                EagerMinds
              </span>
            </div>
            <button onClick={() => setIsMobileMenuOpen(false)} className="md:hidden p-1 text-stone-500 hover:text-stone-900 cursor-pointer">
              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-5 h-5">
                <path strokeLinecap="round" strokeLinejoin="round" d="M6 18L18 6M6 6l12 12" />
              </svg>
            </button>
          </div>

          {/* Main Navigation Section */}
          <nav className="p-4 flex flex-col gap-1.5">
            <button
              onClick={() => { setActiveTab("vault"); setSelectedTag(null); setIsMobileMenuOpen(false); }}
              className={`w-full flex items-center justify-between px-4 py-3 rounded-xl text-left text-xs font-bold uppercase tracking-wider transition-all duration-300 cursor-pointer ${
                activeTab === "vault" && !selectedTag
                  ? "bg-stone-900 text-white shadow-[0_10px_20px_-5px_rgba(0,0,0,0.15)]"
                  : "text-stone-500 hover:bg-stone-200/45 hover:text-stone-900"
              }`}
            >
              <span className="flex items-center gap-3">
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.2} stroke="currentColor" className="w-4 h-4">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M2.25 13.5h3.86a2.25 2.25 0 012.008 1.24l.885 1.77a2.25 2.25 0 002.007 1.24h1.98a2.25 2.25 0 002.007-1.24l.885-1.77a2.25 2.25 0 012.007-1.24h3.86m-18 0h18a2.25 2.25 0 012.25 2.25v4.5A2.25 2.25 0 0118 21H6a2.25 2.25 0 01-2.25-2.25v-4.5a2.25 2.25 0 012.25-2.25zM6 7.5h12M9 3h6" />
                </svg>
                Private Vault
              </span>
              <span className={`font-mono text-[10px] px-2 py-0.5 rounded-full ${activeTab === "vault" && !selectedTag ? "bg-white/20 text-white" : "bg-stone-200/80 text-stone-600"}`}>
                {bookmarks.length}
              </span>
            </button>

            <button
              onClick={() => { setActiveTab("bio"); setIsMobileMenuOpen(false); }}
              className={`w-full flex items-center justify-between px-4 py-3 rounded-xl text-left text-xs font-bold uppercase tracking-wider transition-all duration-300 cursor-pointer ${
                activeTab === "bio"
                  ? "bg-stone-900 text-white shadow-[0_10px_20px_-5px_rgba(0,0,0,0.15)]"
                  : "text-stone-500 hover:bg-stone-200/45 hover:text-stone-900"
              }`}
            >
              <span className="flex items-center gap-3">
                <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.2} stroke="currentColor" className="w-4 h-4">
                  <path strokeLinecap="round" strokeLinejoin="round" d="M10.5 1.5H8.25A2.25 2.25 0 006 3.75v16.5a2.25 2.25 0 002.25 2.25h7.5A2.25 2.25 0 0018 20.25V3.75a2.25 2.25 0 00-2.25-2.25H13.5m-3 0V3h3V1.5m-3 0h3m-3 18.75h3" />
                </svg>
                Bio Link Profile
              </span>
              <span className={`font-mono text-[10px] px-2 py-0.5 rounded-full ${activeTab === "bio" ? "bg-white/20 text-white" : "bg-stone-200/80 text-stone-600"}`}>
                {bookmarks.filter((b) => b.isPublic).length}
              </span>
            </button>
          </nav>

          {/* Quick Tags Filter Section */}
          <div className="mt-8 px-6">
            <span className="text-[9px] font-black tracking-widest uppercase text-stone-400">Vault Tags</span>
            <div className="mt-3 flex flex-col gap-1 max-h-48 overflow-y-auto scrollbar-none">
              {uniqueTags.map((tag) => (
                <button
                  key={tag}
                  onClick={() => { setActiveTab("vault"); setSelectedTag(tag); setIsMobileMenuOpen(false); }}
                  className={`w-full flex items-center justify-between py-1.5 text-xs font-bold lowercase transition-colors cursor-pointer ${
                    selectedTag === tag ? "text-stone-900" : "text-stone-400 hover:text-stone-700"
                  }`}
                >
                  <span className="flex items-center gap-2">
                    <span className="h-1.5 w-1.5 rounded-full bg-stone-300" />
                    #{tag}
                  </span>
                  <span className="font-mono text-[8px]">
                    {bookmarks.filter((b) => b.tag.toLowerCase() === tag).length}
                  </span>
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* User Account Controls */}
        <div className="p-4 border-t border-stone-200/40 bg-stone-100/30 flex flex-col gap-2">
          <div className="flex items-center gap-3 px-2 py-1.5">
            <div className="h-8 w-8 rounded-full bg-stone-900 flex items-center justify-center font-black text-xs text-white border border-stone-450/10 shadow-inner">
              {userProfile?.full_name ? userProfile.full_name.charAt(0).toUpperCase() : (userProfile?.handle ? userProfile.handle.charAt(0).toUpperCase() : "U")}
            </div>
            <div className="flex flex-col text-left max-w-[150px]">
              <span className="text-[10px] font-black tracking-wide text-stone-800 truncate">
                {userProfile?.full_name || userProfile?.handle || "User"}
              </span>
              <span className="text-[8px] font-bold text-stone-400 uppercase tracking-widest mt-0.5 truncate">
                {userProfile?.handle ? `@${userProfile.handle}` : "Vault Owner"}
              </span>
            </div>
          </div>

          <button
            onClick={handleSignOut}
            className="w-full flex items-center gap-3 px-4 py-2.5 rounded-xl text-left text-[10px] font-black uppercase tracking-widest text-red-500 hover:bg-red-50 transition-colors cursor-pointer"
          >
            <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-3.5 h-3.5">
              <path strokeLinecap="round" strokeLinejoin="round" d="M15.75 9V5.25A2.25 2.25 0 0013.5 3h-6a2.25 2.25 0 00-2.25 2.25v13.5A2.25 2.25 0 007.5 21h6a2.25 2.25 0 002.25-2.25V15M12 9l-3 3m0 0l3 3m-3-3h12.75" />
            </svg>
            Sign Out
          </button>
        </div>
      </aside>

      {/* 2. Main content Explorer */}
      <main className="flex-1 flex flex-col h-full bg-[#FAF8F5] relative z-20 overflow-hidden">

        {/* Workspace Toolbar Header */}
        <header className="h-20 border-b border-stone-200/40 px-4 md:px-8 flex items-center justify-between shrink-0 bg-white/35 backdrop-blur-md gap-3 md:gap-4">
          <div className="flex items-center gap-2 shrink-0">
            {/* Mobile menu toggle */}
            <button
              onClick={() => setIsMobileMenuOpen(true)}
              className="md:hidden p-2 -ml-2 text-stone-500 hover:text-stone-900 transition-colors cursor-pointer"
            >
              <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" className="w-5 h-5">
                <path strokeLinecap="round" strokeLinejoin="round" d="M3.75 6.75h16.5M3.75 12h16.5m-16.5 5.25h16.5" />
              </svg>
            </button>

            {/* Back button next to search bar */}
